        private async Task<(bool IsValid, string ErrorMessage)> ValidateFile(IFormFile file)
        {
            if (file.Length > MaxFileSize)
                return (false, "File size exceeds maximum limit of 10MB.");

            var extension = Path.GetExtension(file.FileName);
            if (!AllowedExtensions.Contains(extension))
                return (false, "File type not allowed.");

            var contentType = file.ContentType;
            if (!AllowedMimeTypes.Contains(contentType))
                return (false, "Content type not allowed.");

            // Additional content validation can be added here
            using (var reader = new StreamReader(file.OpenReadStream()))
            {
                var buffer = new byte[4];
                await reader.BaseStream.ReadAsync(buffer, 0, 4);
                var header = BitConverter.ToString(buffer).Replace("-", "").ToUpperInvariant();

                // Validate image headers
                if (contentType.StartsWith("image/"))
                {
                    if (!IsImageValid(header))
                        return (false, "Invalid image file.");
                }
            }

            return (true, null);
        }

        private bool IsImageValid(string header)
        {
            // Simple header validation for common image formats
            return header.StartsWith("FFD8") || // JPEG
                   header.StartsWith("89504E47") || // PNG
                   header.StartsWith("47494638") || // GIF
                   header.StartsWith("424D"); // BMP
